import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { OrderItem } from '../../src/entities/order-item.entity';
import { buildOrderItem } from '../factories/order-item.factory';
import { Order } from '../../src/entities/order.entity';
import { buildOrder } from '../factories/order.factory';

describe('OrderItem Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<OrderItem>;
  let orderId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(OrderItem);
  });

  beforeEach(async () => {
    const orderEntity = await dataSource
      .getRepository(Order)
      .save(
        dataSource.getRepository(Order).create(
          buildOrder(),
        ),
      );
    orderId = orderEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('belongs_to Order', () => {
    it('persists orderId reference', async () => {
      const data = buildOrderItem({ orderId: orderId });
      const saved = await repository.save(repository.create(data));
      expect(saved.orderId).toBe(orderId);
    });

    it('loads parent via relation', async () => {
      const data = buildOrderItem({ orderId: orderId });
      const saved = await repository.save(repository.create(data));
      const loaded = await repository.findOne({
        where: { id: saved.id } as Record<string, unknown>,
        relations: ['order'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.order).toBeDefined();
      expect(loaded!.order.id).toBe(orderId);
    });

    it('rejects entity without required orderId', async () => {
      const data = buildOrderItem({ orderId: undefined as unknown as string });
      await expect(
        repository.save(repository.create(data)),
      ).rejects.toThrow();
    });
  });
});
